def _generate_transaction_id():
    import uuid
    return f"TXN-{uuid.uuid4().hex[:12].upper()}"


def _validate_account(account_id):
    if account_id not in ACCOUNTS_DB:
        raise Fault(
            faultcode="Client.AccountNotFound",
            faultstring=f"Account '{account_id}' not found in our system.",
        )
    account = ACCOUNTS_DB[account_id]
    if account["status"] != "active":
        raise Fault(
            faultcode="Client.AccountInactive",
            faultstring=f"Account '{account_id}' is not active. Current status: {account['status']}",
        )
    return account


