    def transferFunds(from_account_id, to_account_id, amount, currency):
        """
        Transfer funds between two accounts.

        SOAPAction: urn:FinancialServices/transferFunds
        """
        logger.info(f"transferFunds called: {from_account_id} -> {to_account_id}, amount: {amount} {currency}")

